import { useQuery } from '@tanstack/react-query';
import { useState } from 'react';
import useDebounce from '@/hooks/useDebounce';

function SearchResult({ isLoading, data }) {
  return (
    <div className="flex w-full flex-col divide-y divide-gray-300 bg-gray-500 px-4 py-2">
      {isLoading && <div className="text-white">Loading...</div>}
      {data && data.map((item) => (
        <div key={item.id} className="py-2 text-gray-100">
          {item.title}
        </div>
      ))}
    </div>
  );
}

export default function Character() {
  const [search, setSearch] = useState('');

  const debouncedSearchTerm = useDebounce(search, 200);

  const { data, isLoading, error } = useQuery({
    queryKey: ['search', debouncedSearchTerm],
    queryFn: async () => {
      if (debouncedSearchTerm) {
        const response = await fetch(`https://naruto-database.p.rapidapi.com/clan?name=${debouncedSearchTerm}`, {
          headers: {
            'X-RapidAPI-Key': '944d0bb5e0mshb3be89706058b7cp19275ajsn34bf651ae782',
            'X-RapidAPI-Host': 'naruto-database.p.rapidapi.com'
          }
        });
        const data = await response.json();
        return data;
      }
      return [];
    },
    onError: (error) => {
      console.error(error);
    }
  });

  return (
    <div>
      <input
        type="search"
        value={search}
        onChange={(e) => setSearch(e.target.value)}
        placeholder="Enter your search term here"
        className="w-full rounded-md bg-gray-600 p-2 text-gray-50 placeholder:text-gray-500 focus:outline-none focus:ring focus:ring-purple-500"
      />
      {data?.length > 0 && <SearchResult isLoading={isLoading} data={data} />}
      {error && <div className="text-red-500">Error: {(error as Error).message}</div>}
    </div>
  );
}










